+  const listToken = listIndex >= 0 ? section.blocks[listIndex] : null;
+  const beforeBlocks = listIndex >= 0 ? section.blocks.slice(0, listIndex) : section.blocks;
+  const afterBlocks = listIndex >= 0 ? section.blocks.slice(listIndex + 1) : [];
