+        {renderBlockTokens(beforeBlocks, onOpenDoc)}
+        <ReadNextGrid
+          items={(listToken.items as MarkdownListItem[] | undefined) ?? []}
+          onOpenDoc={onOpenDoc}
+        />
+        {renderBlockTokens(afterBlocks, onOpenDoc)}
+      </>
+    );
+  }
